create extension if not exists pgcrypto;
create table if not exists platform_installation (id text primary key default 'default', installation_complete boolean not null default false, installed_version text, installed_at timestamptz, installed_by_user_id uuid, current_step text not null default 'welcome', license_status text not null default 'not_checked', bootstrap_generated boolean not null default false, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
insert into platform_installation(id) values ('default') on conflict (id) do nothing;
create table if not exists platform_secret_settings (id uuid primary key default gen_random_uuid(), key text not null unique, encrypted_value text not null, provider text not null default 'encrypted_db', last_four text, status text not null default 'configured', last_tested_at timestamptz, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists platform_license_settings (id text primary key default 'default', license_key text, license_status text not null default 'verification_disabled', license_plan text, license_holder text, license_expires_at timestamptz, validation_enabled boolean not null default false, verification_provider text, last_checked_at timestamptz, last_success_at timestamptz, last_error text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
insert into platform_license_settings(id) values ('default') on conflict (id) do nothing;
create table if not exists companies (id uuid primary key default gen_random_uuid(), name text not null, settings jsonb not null default '{}'::jsonb, theme jsonb not null default '{}'::jsonb, homepage jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists users (id uuid primary key default gen_random_uuid(), full_name text not null, email text not null unique, phone text, role text not null default 'client', created_at timestamptz not null default now());
create table if not exists roles (key text primary key, label text not null, permissions jsonb not null default '[]'::jsonb);
create table if not exists permissions (key text primary key, label text not null, module_id text, default_roles jsonb not null default '[]'::jsonb);
create table if not exists module_registry (id text primary key, manifest jsonb not null, enabled boolean not null default true, visibility jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists workflow_items (id uuid primary key default gen_random_uuid(), type text not null, status text not null, payload jsonb not null default '{}'::jsonb, archived_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists audit_logs (id uuid primary key default gen_random_uuid(), actor_user_id uuid, action text not null, target_type text, target_id text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists ai_runs (id uuid primary key default gen_random_uuid(), feature text not null, model text, status text not null, redacted_input jsonb not null default '{}'::jsonb, redacted_output jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists platform_files (id uuid primary key default gen_random_uuid(), category text not null, visibility text not null default 'private', file_name text not null, mime_type text, storage_url text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
